import React from "react";
import { Chip } from "@mui/material";

const skills = [
  { name: "HTML", emoji: "🌐", color: "#2196F3" }, // Blue
  { name: "CSS", emoji: "🎨", color: "#E91E63" }, // Pink
  { name: "JavaScript", emoji: "⚡", color: "#4CAF50" }, // Green
  { name: "TypeScript", emoji: "🛠️", color: "#00BCD4" }, // Cyan
  { name: "React", emoji: "⚛️", color: "#3F51B5" }, // Indigo
  { name: "React Native", emoji: "📱", color: "#673AB7" }, // Deep Purple
  { name: "Django", emoji: "🐍", color: "#8BC34A" }, // Light Green
  { name: "Python", emoji: "🐍", color: "#FF9800" }, // Orange
  { name: "Azure", emoji: "☁️", color: "#03A9F4" }, // Light Blue
  { name: "Share Hosting", emoji: "📡", color: "#795548" }, // Brown
  { name: "Digital Ocean", emoji: "🌊", color: "#009688" }, // Teal
  { name: "Mac", emoji: "🍏", color: "#607D8B" }, // Blue Grey
  { name: "Windows", emoji: "🖥️", color: "#1E88E5" }, // Dark Blue
  { name: "Linux", emoji: "🐧", color: "#000000" } // Black
];

export default function Skills() {
  return (
    <div
      style={{
        textAlign: "center",
        backgroundColor: "#121212",
        color: "white",
        padding: "40px 20px",
        borderRadius: "10px"
      }}
    >
      <h2 style={{ fontSize: "32px", marginBottom: "20px",textAlign:"left" }}>💻 My Skills</h2>
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          justifyContent: "flex-start",
          gap: "10px"
        }}
      >
        {skills.map((skill, index) => (
          <Chip
            key={index}
            label={`${skill.emoji} ${skill.name}`}
            style={{
              backgroundColor: skill.color,
              color: "white",
              fontSize: "16px",
              fontWeight: "bold",
              padding: "10px",
              cursor: "pointer"
            }}
          />
        ))}
      </div>
    </div>
  );
}
